// Parse AI Response
const inputData = $input.first();
if (!inputData?.json) {
  console.log('❌ 沒有輸入數據，停止執行');
  return [{ json: { status: 'error', error: '沒有輸入數據' } }];
}

const aiResponseText = inputData.json.text || inputData.json.output;
if (!aiResponseText) {
  console.log('❌ AI 沒有輸出文字，停止執行');
  return [{ json: { status: 'error', error: 'AI 沒有輸出文字' } }];
}

let aiOutput;
try {
  const cleanResponse = aiResponseText.replace(/```json\n?|```\n?/g, '').trim();
  aiOutput = JSON.parse(cleanResponse);
} catch (error) {
  console.log('❌ JSON 解析失敗:', error.message);
  return [{ json: { status: 'error', error: `AI 回應解析失敗: ${error.message}`, rawResponse: aiResponseText, slackUser: 'unknown', slackChannel: 'unknown', slackTimestamp: Date.now().toString() } }];
}

let slackData;
try {
  slackData = $('Slack Message Trigger').first().json;
} catch (error) {
  console.log('⚠️ 取得 Slack 數據失敗:', error.message);
  slackData = { text: '無法取得原始訊息', user: 'unknown', channel: 'unknown', ts: Date.now().toString() };
}

if (!aiOutput.hasEvent || !aiOutput.events || aiOutput.events.length === 0) {
  console.log('ℹ️ AI 沒有找到事件');
  return [{ json: { status: 'no_event', message: '未找到有效的日程信息', originalMessage: slackData.text, slackUser: slackData.user, slackChannel: slackData.channel, slackTimestamp: slackData.ts, reasoning: aiOutput.reasoning || '無法識別日程相關內容' } }];
}

console.log(`📅 找到 ${aiOutput.events.length} 個事件，開始處理`);

try {
  const processedEvents = aiOutput.events.map((event, index) => {
    if (!event.title || !event.startDateTime) {
      console.log(`⚠️ 事件 ${index} 缺少必要欄位 (title=${event.title}, startDateTime=${event.startDateTime})，跳過`);
      return null;
    }
    let startDateTime, endDateTime, isAllDay = false;
    try {
      const isAllDayEvent = event.isAllDay === true || (!event.startDateTime.includes('T') && !event.endDateTime.includes('T'));
      if (isAllDayEvent) {
        isAllDay = true;
        startDateTime = event.startDateTime.includes('T') ? event.startDateTime.split('T')[0] : event.startDateTime;
        endDateTime = event.endDateTime.includes('T') ? event.endDateTime.split('T')[0] : event.endDateTime;
        if (!/^\d{4}-\d{2}-\d{2}$/.test(startDateTime)) throw new Error(`全天活動日期格式錯誤: ${startDateTime}`);
        console.log(`✅ 事件 ${index} 全天活動: ${startDateTime}`);
      } else {
        const startDate = new Date(event.startDateTime);
        const endDate = new Date(event.endDateTime);
        if (isNaN(startDate.getTime()) || isNaN(endDate.getTime())) throw new Error(`無效的日期時間格式: start=${event.startDateTime}, end=${event.endDateTime}`);
        if (endDate <= startDate) endDate.setTime(startDate.getTime() + 3600000);
        startDateTime = startDate.toISOString();
        endDateTime = endDate.toISOString();
        console.log(`✅ 事件 ${index} 定時活動: ${startDateTime} ~ ${endDateTime}`);
      }
    } catch (dateError) {
      console.log(`⚠️ 事件 ${index} 時間處理失敗: ${dateError.message}，使用明天作為預設`);
      const tomorrow = new Date(); tomorrow.setDate(tomorrow.getDate() + 1);
      const dateStr = tomorrow.toISOString().split('T')[0];
      startDateTime = dateStr; endDateTime = dateStr; isAllDay = true;
    }
    const attendees = (event.attendees || []).filter(e => e?.includes('@') && e.includes('.'));
    const confidence = parseFloat(event.confidence) || 0.5;
    const description = [event.description || '', '', '📋 來源信息：', `• Slack 訊息: ${slackData.text}`, `• 發送者: <@${slackData.user}>`, `• 頻道: <#${slackData.channel}>`, `• 活動類型: ${isAllDay ? '📅 全天活動' : '⏰ 部分時間活動'}`, `• AI 分析信心度: ${Math.round(confidence * 100)}%`, aiOutput.reasoning ? `• 分析說明: ${aiOutput.reasoning}` : ''].filter(line => line !== '').join('\n');
    return { json: { eventIndex: index, title: event.title, description, startDateTime, endDateTime, isAllDay, location: event.location || '', attendees, confidence, confidenceDisplay: `${Math.round(confidence * 100)}%`, reasoning: aiOutput.reasoning || '', originalMessage: slackData.text, slackUser: slackData.user, slackChannel: slackData.channel, slackTimestamp: slackData.ts, status: confidence >= 0.7 ? 'high_confidence' : 'low_confidence' } };
  }).filter(event => event !== null);
  if (processedEvents.length === 0) {
    console.log('⚠️ 所有事件都無效，回傳 no_event');
    return [{ json: { status: 'no_event', message: '所有事件都無效', originalMessage: slackData.text, slackUser: slackData.user, slackChannel: slackData.channel, slackTimestamp: slackData.ts, reasoning: aiOutput.reasoning || '' } }];
  }
  console.log(`🎉 成功處理 ${processedEvents.length} 個事件`);
  return processedEvents;
} catch (error) {
  console.log('❌ 處理事件時發生未預期錯誤:', error.message, error.stack);
  return [{ json: { status: 'error', error: `處理失敗: ${error.message}`, originalMessage: slackData?.text || 'unknown', slackUser: slackData?.user || 'unknown', slackChannel: slackData?.channel || 'unknown', slackTimestamp: slackData?.ts || Date.now().toString() } }];
}

